// Очистка и трансформация машин
const items = $input.all();
if (!items || items.length === 0) return [];

// Разворачиваем массив если данные вложены
let data = items;
if (items[0].json && Array.isArray(items[0].json)) {
  data = items[0].json.map(v => ({ json: v }));
} else if (Array.isArray(items[0].json?.value)) {
  data = items[0].json.value.map(v => ({ json: v }));
}

function esc(s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/'/g, "''");
}

const result = [];
for (const item of data) {
  const v = item.json || item;
  const id = esc(v.id || v.Ref_Key || '');
  const plate = esc(v.license_plate || v.ГосНомер || v.RegNumber || '');
  const model = esc(v.model || v.Модель || v.Model || v.Description || '');

  if (id) {
    result.push({ json: { id, license_plate: plate, model } });
  }
}

console.log('Vehicles:', result.length);
return result;

// Очистка и трансформация водителей
const items = $input.all();
if (!items || items.length === 0) return [];

let data = items;
if (items[0].json && Array.isArray(items[0].json)) {
  data = items[0].json.map(d => ({ json: d }));
} else if (Array.isArray(items[0].json?.value)) {
  data = items[0].json.value.map(d => ({ json: d }));
}

function esc(s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/'/g, "''");
}

const result = [];
for (const item of data) {
  const d = item.json || item;
  const id = esc(d.id || d.Ref_Key || d.full_name || '');
  const name = esc(d.full_name || d.ФИО || d.Description || d.name || '');

  if (id && name) {
    result.push({ json: { id, full_name: name } });
  }
}

console.log('Drivers:', result.length);
return result;

// Очистка и трансформация контрактов
const items = $input.all();
if (!items || items.length === 0) return [];

let data = items;
if (items[0].json && Array.isArray(items[0].json)) {
  data = items[0].json.map(c => ({ json: c }));
} else if (Array.isArray(items[0].json?.value)) {
  data = items[0].json.value.map(c => ({ json: c }));
}

function esc(s) {
  if (s === null || s === undefined) return '';
  return String(s).replace(/'/g, "''");
}

const result = [];
for (const item of data) {
  const c = item.json || item;
  const number = esc(c.number || c.Номер || '');
  const date = c.date || c.Дата || null;

  if (number && date) {
    result.push({
      json: {
        number,
        date,
        organization: esc(c.organization || c.Организация || ''),
        contractor_id: esc(c.contractor_id || c.Контрагент_Key || ''),
        contractor_name: esc(c.contractor_name || c.Контрагент || ''),
        vehicle_id: esc(c.vehicle_id || c.ТС_Key || ''),
        vehicle_number: esc(c.vehicle_number || c.ГосНомер || ''),
        driver_id: esc(c.driver_id || c.Водитель_Key || ''),
        driver_name: esc(c.driver_name || c.Водитель || ''),
        responsible_logist: esc(c.responsible_logist || c.ОтветственныйЛогист || ''),
        route: esc(c.route || c.Маршрут || ''),
        payment_term: esc(c.payment_term || c.УсловияОплаты || ''),
        payment_condition: esc(c.payment_condition || c.СрокОплаты || ''),
        amount: parseFloat(c.amount || c.Сумма || 0) || 0
      }
    });
  }
}

console.log('Contracts:', result.length);
return result;

// Создаём отчёт о синхронизации
let vehiclesCount = 0;
let driversCount = 0;
let contractsCount = 0;

try {
  vehiclesCount = $('Transform: Vehicles').all().length;
} catch(e) {}

try {
  driversCount = $('Transform: Drivers').all().length;
} catch(e) {}

try {
  contractsCount = $('Transform: Contracts').all().length;
} catch(e) {}

const report = {
  sync_time: new Date().toISOString(),
  vehicles: vehiclesCount,
  drivers: driversCount,
  contracts: contractsCount,
  total: vehiclesCount + driversCount + contractsCount,
  status: 'SUCCESS'
};

console.log('SYNC REPORT:', JSON.stringify(report));

return [{ json: report }];

